+fn normalize_dot_body(body: &str) -> String {
+    let mut output = String::with_capacity(body.len().saturating_mul(2));
+    let mut quote_char: Option<char> = None;
+    let mut escaped = false;
+
+    for ch in body.chars() {
+        if let Some(active_quote) = quote_char {
+            output.push(ch);
+            if escaped {
+                escaped = false;
+                continue;
+            }
+            if ch == '\\' {
+                escaped = true;
+                continue;
+            }
+            if ch == active_quote {
+                quote_char = None;
+            }
+            continue;
+        }
+
+        match ch {
+            '"' | '\'' => {
+                quote_char = Some(ch);
+                output.push(ch);
+            }
+            '{' | '}' => {
+                output.push(';');
+                output.push(ch);
+                output.push(';');
+            }
+            _ => output.push(ch),
+        }
+    }
+
+    output
+}
+
+fn clean_optional(raw: &str) -> Option<String> {
+    let cleaned = raw
+        .trim()
+        .trim_matches('"')
+        .trim_matches('\'')
+        .trim();
+    (!cleaned.is_empty()).then_some(cleaned.to_string())
+}
+
+fn decode_escapes(raw: &str) -> String {
+    let mut output = String::with_capacity(raw.len());
+    let mut escaped = false;
+
+    for ch in raw.chars() {
+        if escaped {
+            let decoded = match ch {
+                'n' => '\n',
+                'r' => '\r',
+                't' => '\t',
+                '\\' => '\\',
+                '"' => '"',
+                '\'' => '\'',
+                other => other,
+            };
+            output.push(decoded);
+            escaped = false;
+            continue;
+        }
+
+        if ch == '\\' {
+            escaped = true;
+        } else {
+            output.push(ch);
+        }
+    }
+
+    if escaped {
+        output.push('\\');
+    }
+    output
+}
+
+fn strip_html_tags(raw: &str) -> String {
+    let mut output = String::with_capacity(raw.len());
+    let mut in_tag = false;
+
+    for ch in raw.chars() {
+        match ch {
+            '<' => in_tag = true,
+            '>' => in_tag = false,
+            _ if !in_tag => output.push(ch),
+            _ => {}
+        }
+    }
+
+    output.trim().to_string()
+}
